enum class Dir { ACROSS, DOWN }

data class PlacedWord(
    val word: String,
    val row: Int,
    val col: Int,
    val dir: Dir,
)

data class Level(
    val rows: Int,
    val cols: Int,
    val letters: List<Char>,
    val words: List<PlacedWord>,
) {
    fun answersSet(): Set<String> = words.map { it.word }.toSet()

    fun usedCells(): Set<Pair<Int, Int>> {
        val used = mutableSetOf<Pair<Int, Int>>()
        for (pw in words) {
            for (i in pw.word.indices) {
                val (r, c) = when (pw.dir) {
                    Dir.ACROSS -> pw.row to (pw.col + i)
                    Dir.DOWN -> (pw.row + i) to pw.col
                }
                used.add(r to c)
            }
        }
        return used
    }

    fun solutionLetterAt(row: Int, col: Int): Char? {
        for (pw in words) {
            for ((i, ch) in pw.word.withIndex()) {
                val (r, c) = when (pw.dir) {
                    Dir.ACROSS -> pw.row to (pw.col + i)
                    Dir.DOWN -> (pw.row + i) to pw.col
                }
                if (r == row && c == col) return ch
            }
        }
        return null
    }

    fun bonusWords(): List<String> = LEVEL_BONUS[letters.joinToString("")] ?: emptyList()

    companion object {
        const val TOTAL_LEVELS = 100

        fun get(levelNum: Int): Level {
            val idx = (levelNum - 1).coerceIn(0, LEVELS.size - 1)
            return LEVELS[idx]
        }
    }
}

